package main

import (
	"fmt"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct email headers
	// Note: In a real-world scenario, you might need to encode non-ASCII subjects using RFC 2047.
	// For this implementation, we assume the subject is ASCII or UTF-8 compatible.
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	// Construct HTML body
	// We escape potential HTML characters in user input to prevent injection into the email structure.
	// While the email is HTML, we want to display the user's content safely.
	escapedUserName := htmlEscape(userName)
	escapedSubject := htmlEscape(subject)
	escapedContent := htmlEscape(feedbackContent)

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedContent,
	)

	// Construct headers
	// We use a strings.Builder for efficient concatenation
	var headersBuilder strings.Builder
	headersBuilder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	headersBuilder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	headersBuilder.WriteString(fmt.Sprintf("Subject: %s\r\n", emailSubject))
	headersBuilder.WriteString("MIME-Version: 1.0\r\n")
	headersBuilder.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	headersBuilder.WriteString("\r\n") // Empty line separating headers from body

	// Combine headers and body
	emailMessage := headersBuilder.String() + htmlBody

	return emailMessage, nil
}

// htmlEscape escapes special HTML characters to prevent injection.
// This is a simple implementation; in production, consider using html.EscapeString from the html package.
func htmlEscape(s string) string {
	// Replace potentially dangerous characters with their HTML entities
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	s = strings.ReplaceAll(s, "'", "&#39;")
	return s
}

