	}

	// Construct email subject
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	// Escape potential special characters in user-provided data to prevent header injection.
	// Specifically, replace carriage return (CR) and line feed (LF) characters with spaces
	// in the subject line and user name to maintain email header integrity.
	escapedSubject := strings.ReplaceAll(emailSubject, "\r", " ")
	escapedSubject = strings.ReplaceAll(escapedSubject, "\n", " ")
	escapedUserName := strings.ReplaceAll(userName, "\r", " ")
