		toAddr,
		// Simple quoted-printable encoding for the subject (escaping equals and spaces)
		strings.ReplaceAll(strings.ReplaceAll(escapedSubject, "=", "=3D"), " ", "=20"),
	)

	// Construct HTML body
	// We use html/template implicitly by context-aware escaping in the sprintf,
	// but since we are generating raw HTML, we must ensure the content is safe.
