	escapedFeedback := strings.ReplaceAll(feedbackContent, "<", "&lt;")
	escapedFeedback = strings.ReplaceAll(escapedFeedback, ">", "&gt;")
	escapedFeedback = strings.ReplaceAll(escapedFeedback, "&", "&amp;")

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
