package main

import (
	"bytes"
	"fmt"
	"html/template"
	"net/smtp"
	"strings"
)

// BuildFeedbackEmail constructs an HTML formatted email body for user feedback
// and prepares the raw email content suitable for use with net/smtp.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the HTML template for the feedback email
	const emailTemplate = `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Feedback Notification</title>
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
        .header { background-color: #f4f4f4; padding: 10px; border-bottom: 1px solid #ddd; }
        .header h1 { margin: 0; font-size: 24px; color: #555; }
        .content { padding: 20px; }
        .info-table { width: 100%; border-collapse: collapse; margin-bottom: 20px; }
        .info-table th, .info-table td { border: 1px solid #ddd; padding: 8px; text-align: left; }
        .info-table th { background-color: #f9f9f9; width: 150px; }
        .feedback-box { background-color: #f9f9f9; padding: 15px; border: 1px solid #ddd; border-radius: 3px; white-space: pre-wrap; }
        .footer { margin-top: 20px; font-size: 12px; color: #777; text-align: center; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h1>New User Feedback Submitted</h1>
        </div>
        <div class="content">
            <p>A new feedback submission has been received from the user portal. Please review the details below:</p>

            <table class="info-table">
                <tr>
                    <th>User Name</th>
                    <td>{{.UserName}}</td>
                </tr>
                <tr>
                    <th>Subject</th>
                    <td>{{.Subject}}</td>
                </tr>
                <tr>
                    <th>Date</th>
                    <td>{{.Date}}</td>
                </tr>
            </table>

            <h3>Feedback Content:</h3>
            <div class="feedback-box">
{{.Content}}
            </div>
        </div>
        <div class="footer">
            <p>This email was sent automatically by the Feedback System.</p>
        </div>
    </div>
</body>
</html>`

	// Data structure to hold template variables
	type emailData struct {
		UserName string
		Subject  string
		Content  string
		Date     string
	}

	// Get current date/time (using a placeholder format for simplicity)
	// In a production environment, you might use time.Now().Format("2006-01-02 15:04:05")
	currentDate := "Date not specified" 

	data := emailData{
		UserName: userName,
		Subject:  subject,
		Content:  feedbackContent,
		Date:     currentDate,
	}

	// Parse the template
	tmpl, err := template.New("email").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Execute the template with data
	var tpl bytes.Buffer
	if err := tmpl.Execute(&tpl, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	htmlContent := tpl.String()

	// Construct the raw email message following RFC 822 / MIME standards
	// This format is compatible with net/smtp
	var msgBuilder strings.Builder

	// Standard headers
	msgBuilder.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	msgBuilder.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	msgBuilder.WriteString(fmt.Sprintf("Subject: %s\r\n", subject))
	msgBuilder.WriteString("MIME-Version: 1.0\r\n")
	msgBuilder.WriteString("Content-Type: text/html; charset=\"UTF-8\"\r\n")

	// Empty line separating headers from body
	msgBuilder.WriteString("\r\n")

	// HTML body
	msgBuilder.WriteString(htmlContent)

	return msgBuilder.String(), nil
}

// main function to demonstrate usage
func main() {
	// Example usage
	from := "feedback@example.com"
	to := "support@example.com"
	user := "John Doe"
	subj := "Issue with Login Functionality"
	content := "I am unable to login to my account. It keeps saying 'Invalid Credentials' even though I am sure the password is correct. Please help."

	emailBody, err := BuildFeedbackEmail(from, to, user, subj, content)
	if err != nil {
