)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize user inputs to prevent HTML injection in the email body
	// Note: We escape HTML entities for the HTML context. 
	// For the subject line, we ensure it is safe for email headers.
	safeUserName := html.EscapeString(userName)
	safeSubject := html.EscapeString(subject)
	safeContent := html.EscapeString(feedbackContent)

	// Construct email headers
	// We prepend "Feedback: " to the subject. Since we are escaping the subject input,
	// the resulting string is safe for the email header value (assuming standard ASCII).
	emailSubject := fmt.Sprintf("Feedback: %s", safeSubject)

	// Construct headers map
	headers := map[string]string{
		"From":         fromAddr,
		"To":           toAddr,
		"Subject":      emailSubject,
		"MIME-Version": "1.0",
		"Content-Type": "text/html; charset=UTF-8",
	}

	// Build the header string
	var headerBuffer bytes.Buffer
	for key, value := range headers {
		// RFC 5322: Header lines must be CRLF terminated.
		// fmt.Fprintf handles the string writing, we append CRLF manually.
		headerBuffer.WriteString(fmt.Sprintf("%s: %s\r\n", key, value))
	}

	// Construct HTML body using sanitized inputs
	// We use the safe variables here to prevent XSS in the rendered email.
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		safeUserName,
		safeSubject,
		safeContent,
	)

	// Combine headers and body
	// Ensure there is exactly one blank line (CRLF) between headers and body.
	emailMessage := headerBuffer.String() + "\r\n" + htmlBody

	return emailMessage, nil
}

