	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		fromAddr,
		toAddr,
		emailSubject,
	)

	// Escape HTML special characters in user inputs to prevent XSS and ensure proper rendering
	escapeHTML := func(s string) string {
		s = strings.ReplaceAll(s, "&", "&amp;")
		s = strings.ReplaceAll(s, "<", "&lt;")
		s = strings.ReplaceAll(s, ">", "&gt;")
		s = strings.ReplaceAll(s, "\"", "&quot;")
		s = strings.ReplaceAll(s, "'", "&#39;")
		return s
	}

	escapedUserName := escapeHTML(userName)
	escapedSubject := escapeHTML(subject)
	escapedContent := escapeHTML(feedbackContent)

	// Construct HTML body
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
