package main

import (
	"bytes"
	"fmt"
	"html"
	"net/mail"
	"strings"
)

// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Sanitize user inputs to prevent XSS and email header injection
	sanitizedUserName := html.EscapeString(userName)
	sanitizedSubject := html.EscapeString(subject)
	sanitizedContent := html.EscapeString(feedbackContent)

	// Construct email headers
	// Use quoted-printable encoding for subject to handle special characters safely
	// Note: In a production environment, consider using a library like `go-mail` for proper encoding
	emailSubject := fmt.Sprintf("Feedback: %s", sanitizedSubject)

	// Validate and sanitize the email subject to prevent header injection
	// Remove any CR or LF characters which could be used for header injection
	emailSubject = strings.ReplaceAll(emailSubject, "\r", "")
	emailSubject = strings.ReplaceAll(emailSubject, "\n", "")

	// Construct headers
	var headersBuffer bytes.Buffer
	headersBuffer.WriteString(fmt.Sprintf("From: %s\r\n", fromAddr))
	headersBuffer.WriteString(fmt.Sprintf("To: %s\r\n", toAddr))
	headersBuffer.WriteString(fmt.Sprintf("Subject: %s\r\n", emailSubject))
	headersBuffer.WriteString("MIME-Version: 1.0\r\n")
	headersBuffer.WriteString("Content-Type: text/html; charset=UTF-8\r\n")
	headersBuffer.WriteString("\r\n")

	// Construct HTML body using sanitized inputs
	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		sanitizedUserName,
		sanitizedSubject,
		sanitizedContent,
	)

	// Combine headers and body
	emailMessage := headersBuffer.String() + htmlBody

	return emailMessage, nil
}

