        .header { background-color: #f4f4f4; padding: 10px; border-bottom: 1px solid #ddd; margin-bottom: 20px; }
        .header h2 { margin: 0; color: #333; }
        .info-table { width: 100%%; border-collapse: collapse; margin-bottom: 20px; }
        .info-table td { padding: 8px; border: 1px solid #ddd; vertical-align: top; }
        .info-table td:first-child { font-weight: bold; width: 20%%; background-color: #f9f9f9; }
        .content-box { background-color: #fff; padding: 15px; border: 1px solid #eee; border-radius: 3px; white-space: pre-wrap; }
