func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Define the HTML template for the email body.
	const emailTemplate = `
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <style>
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        .container { max-width: 600px; margin: 0 auto; padding: 20px; border: 1px solid #ddd; border-radius: 5px; }
        .header { background-color: #f4f4f4; padding: 10px; border-bottom: 1px solid #ddd; }
        .header h2 { margin: 0; color: #0056b3; }
        .content { padding: 20px; }
        .label { font-weight: bold; color: #555; }
        .value { margin-bottom: 15px; padding: 10px; background-color: #f9f9f9; border-left: 4px solid #0056b3; }
        .footer { margin-top: 20px; font-size: 0.8em; color: #777; text-align: center; }
    </style>
</head>
<body>
    <div class="container">
        <div class="header">
            <h2>New User Feedback Submission</h2>
        </div>
        <div class="content">
            <p>The following feedback was received from the user:</p>

            <div class="label">User Name:</div>
            <div class="value">{{ .UserName }}</div>

            <div class="label">Feedback Subject:</div>
            <div class="value">{{ .Subject }}</div>

            <div class="label">Feedback Content:</div>
            <div class="value">{{ .FeedbackContent }}</div>
        </div>
        <div class="footer">
            <p>Generated at: {{ .Timestamp }}</p>
        </div>
    </div>
</body>
</html>`

	// Parse the template.
	tmpl, err := template.New("email").Parse(emailTemplate)
	if err != nil {
		return "", fmt.Errorf("failed to parse email template: %w", err)
	}

	// Prepare the data for the template.
	data := EmailData{
		UserName:        userName,
		Subject:         subject,
		FeedbackContent: feedbackContent,
		Timestamp:       time.Now().Format(time.RFC1123),
	}

	// Execute the template with data into a buffer.
	var bodyBuffer bytes.Buffer
	if err := tmpl.Execute(&bodyBuffer, data); err != nil {
		return "", fmt.Errorf("failed to execute email template: %w", err)
	}

	// Use net/smtp to construct the full email message including headers.
	// This ensures the email is formatted correctly for SMTP transmission.
	mimeHeaders := "MIME-Version: 1.0\r\n" +
		"Content-Type: text/html; charset=\"UTF-8\"\r\n" +
		"Content-Transfer-Encoding: 7bit\r\n"

	msg := []byte(
		"To: " + toAddr + "\r\n" +
			"From: " + fromAddr + "\r\n" +
			"Subject: " + subject + "\r\n" +
			mimeHeaders + "\r\n" +
			bodyBuffer.String(),
	)

	// smtp package is primarily used for sending, but here we use it to format 
	// the message structure. In a real application, you would call smtp.SendMail 
	// with this constructed message.
	_ = smtp.SendMail

	return string(msg), nil
}

func main() {
	// Example usage of the BuildFeedbackEmail function.
	from := "feedback@example.com"
	to := "support@example.com"
	user := "John Doe"
	subj := "Issue with login page"
	content := "I am unable to log in to my account using my mobile device. The 'Forgot Password' link also seems unresponsive."

	email, err := BuildFeedbackEmail(from, to, user, subj, content)
	if err != nil {
		fmt.Printf("Error generating email: %v\n", err)
		return
	}

	fmt.Println("Generated Email Body:")
	fmt.Println("--------------------------------------------------")
	fmt.Println(email)
	fmt.Println("--------------------------------------------------")
}

