// BuildFeedbackEmail constructs a complete RFC 5322-compliant email message
// with HTML body containing user feedback information.
// The returned emailBody includes headers and body, ready to be sent via smtp.SendMail.
func BuildFeedbackEmail(fromAddr string, toAddr string, userName string, subject string, feedbackContent string) (emailBody string, err error) {
	// Basic validation
	if fromAddr == "" || toAddr == "" {
		return "", fmt.Errorf("fromAddr and toAddr must not be empty")
	}

	// Validate email addresses format (optional but good practice)
	if _, err := mail.ParseAddress(fromAddr); err != nil {
		return "", fmt.Errorf("invalid fromAddr: %w", err)
	}
	if _, err := mail.ParseAddress(toAddr); err != nil {
		return "", fmt.Errorf("invalid toAddr: %w", err)
	}

	// Construct email headers
	emailSubject := fmt.Sprintf("Feedback: %s", subject)

	// Sanitize user input to prevent header injection
	// Replace any CR or LF characters in user-controlled fields with spaces
	safeUserName := strings.ReplaceAll(userName, "\r", " ")
	safeUserName = strings.ReplaceAll(safeUserName, "\n", " ")
	safeSubject := strings.ReplaceAll(emailSubject, "\r", " ")
	safeSubject = strings.ReplaceAll(safeSubject, "\n", " ")
	safeFromAddr := strings.ReplaceAll(fromAddr, "\r", " ")
	safeFromAddr = strings.ReplaceAll(safeFromAddr, "\n", " ")
	safeToAddr := strings.ReplaceAll(toAddr, "\r", " ")
	safeToAddr = strings.ReplaceAll(safeToAddr, "\n", " ")

	// Use quoted-printable or base64 if subject has non-ASCII, but assume ASCII for simplicity
	headers := fmt.Sprintf("From: %s\r\nTo: %s\r\nSubject: %s\r\nMIME-Version: 1.0\r\nContent-Type: text/html; charset=UTF-8\r\n\r\n",
		safeFromAddr,
		safeToAddr,
		safeSubject,
	)

	// Construct HTML body
	// Sanitize feedback content for HTML context to prevent XSS
	// We escape HTML special characters
	escapedFeedbackContent := strings.ReplaceAll(feedbackContent, "&", "&amp;")
	escapedFeedbackContent = strings.ReplaceAll(escapedFeedbackContent, "<", "&lt;")
	escapedFeedbackContent = strings.ReplaceAll(escapedFeedbackContent, ">", "&gt;")
	escapedFeedbackContent = strings.ReplaceAll(escapedFeedbackContent, "\"", "&quot;")
	escapedFeedbackContent = strings.ReplaceAll(escapedFeedbackContent, "'", "&#39;")

	// Also sanitize userName for HTML context
	escapedUserName := strings.ReplaceAll(safeUserName, "&", "&amp;")
	escapedUserName = strings.ReplaceAll(escapedUserName, "<", "&lt;")
	escapedUserName = strings.ReplaceAll(escapedUserName, ">", "&gt;")
	escapedUserName = strings.ReplaceAll(escapedUserName, "\"", "&quot;")
	escapedUserName = strings.ReplaceAll(escapedUserName, "'", "&#39;")

	// Sanitize subject for HTML context (though it's in a title tag)
	escapedSubject := strings.ReplaceAll(safeSubject, "&", "&amp;")
	escapedSubject = strings.ReplaceAll(escapedSubject, "<", "&lt;")
	escapedSubject = strings.ReplaceAll(escapedSubject, ">", "&gt;")
	escapedSubject = strings.ReplaceAll(escapedSubject, "\"", "&quot;")
	escapedSubject = strings.ReplaceAll(escapedSubject, "'", "&#39;")

	htmlBody := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>User Feedback</title>
</head>
<body>
  <h2>User Feedback Received</h2>
  <p><strong>Submitted by:</strong> %s</p>
  <p><strong>Subject:</strong> %s</p>
  <div><strong>Message:</strong><br>
    <pre style="font-family: Arial, sans-serif; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd;">%s</pre>
  </div>
</body>
</html>`,
		escapedUserName,
		escapedSubject,
		escapedFeedbackContent,
	)

	// Combine headers and body
	emailMessage := headers + htmlBody

	return emailMessage, nil
}

