	// Construct the email headers required by SMTP
	// Note: The "MIME-Version" and "Content-Type" headers allow us to send HTML content.
	var headers []string
	headers = append(headers, fmt.Sprintf("From: %s", fromAddr))
	headers = append(headers, fmt.Sprintf("To: %s", toAddr))
