        .info-table td { padding: 8px; border: 1px solid #ddd; vertical-align: top; }
        .info-table td:first-child { font-weight: bold; background-color: #f9f9f9; width: 120px; }
        .content { white-space: pre-wrap; background-color: #f9f9f9; padding: 10px; border: 1px solid #ddd; }
        .footer { margin-top: 20px; font-size: 0.8em; color: #777; text-align: center; }
    </style>
</head>
